namespace ProductReviewsMvc.Infrastructure
{
    public static class ReviewFormatter
    {
        public static IHtmlString ToSafeFormattedHtml(string input)
        {
            if (string.IsNullOrWhiteSpace(input))
            {
                return new HtmlString(string.Empty);
            }

            var encoded = HttpUtility.HtmlEncode(input);

            encoded = encoded.Replace("\r\n", "\n").Replace("\r", "\n");
            encoded = encoded.Replace("**", "\u0001");
            encoded = encoded.Replace("*", "\u0002");

            encoded = ReplacePairedTokens(encoded, "\u0001", "<strong>", "</strong>");
            encoded = ReplacePairedTokens(encoded, "\u0002", "<em>", "</em>");

            encoded = encoded.Replace("\n", "<br />");

            return new HtmlString(encoded);
        }

        private static string ReplacePairedTokens(string input, string token, string openTag, string closeTag)
        {
            var parts = input.Split(new[] { token }, StringSplitOptions.None);
            if (parts.Length == 1)
            {
                return input;
            }

            for (var i = 1; i < parts.Length; i += 2)
            {
                parts[i - 1] += openTag;
                parts[i] += closeTag;
            }

            if ((parts.Length - 1) % 2 != 0)
            {
                parts[parts.Length - 1] = token + parts[parts.Length - 1];
            }

            return string.Concat(parts);
        }
    }
}

namespace ProductReviewsMvc.Controllers
{
    using ProductReviewsMvc.Infrastructure;
    using ProductReviewsMvc.Models;

    public class ProductController : Controller
    {
        private readonly AppDbContext _db;

        public ProductController() : this(new AppDbContext())
        {
        }

        public ProductController(AppDbContext db)
        {
            _db = db;
        }

        public ActionResult Details(int id)
        {
            var product = _db.Products
                .Include(p => p.Reviews)
                .SingleOrDefault(p => p.Id == id);

            if (product == null)
            {
                return HttpNotFound();
            }

            var model = new ProductReviewViewModel
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Reviews = product.Reviews
                    .OrderByDescending(r => r.CreatedAtUtc)
                    .Select(r => new ReviewDisplayViewModel
                    {
                        AuthorName = r.AuthorName,
                        CreatedAtUtc = r.CreatedAtUtc,
                        FormattedContent = ReviewFormatter.ToSafeFormattedHtml(r.Content)
                    })
                    .ToList()
            };

            return View(model);
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _db.Dispose();
            }

            base.Dispose(disposing);
        }
    }
}

/* Views/Product/Details.cshtml */
@model ProductReviewsMvc.Models.ProductReviewViewModel

@{
    ViewBag.Title = Model.ProductName;
}

<h1>@Model.ProductName</h1>

<section class="reviews">
    <h2>Reviews</h2>

    @if (Model.Reviews == null || !Model.Reviews.Any())
    {
        <p>No reviews yet.</p>
    }
    else
    {
        foreach (var review in Model.Reviews)
        {
            <article class="review">
                <header>
                    <strong>@review.AuthorName</strong>
                    <span> - @review.CreatedAtUtc.ToLocalTime().ToString("g")</span>
                </header>
                <div class="review-content">
                    @review.FormattedContent
                </div>
            </article>
        }
    }
}